package com.example.enterprise.service;

import com.example.enterprise.domain.UserEntity;
import com.example.enterprise.domain.UserStatus;
import com.example.enterprise.repository.UserRepository;
import com.example.enterprise.service.dto.CreateUserRequest;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class UserService {

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public UserEntity create(CreateUserRequest req) {
        if (userRepository.existsByUsername(req.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(req.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }

        UserEntity u = new UserEntity();
        u.setUsername(req.getUsername());
        u.setEmail(req.getEmail());
        u.setDisplayName(req.getDisplayName());
        u.setStatus(UserStatus.ACTIVE);
        return userRepository.save(u);
    }

    @Transactional(readOnly = true)
    public UserEntity get(Long id) {
        return userRepository.findById(id).orElseThrow(() -> new EntityNotFoundException("User not found"));
    }

    @Transactional(readOnly = true)
    public Page<UserEntity> list(UserStatus status, Pageable pageable) {
        if (status == null) return userRepository.findAll(pageable);
        return userRepository.findAllByStatus(status, pageable);
    }

    @Transactional
    public UserEntity disable(Long id) {
        UserEntity u = get(id);
        u.setStatus(UserStatus.DISABLED);
        return userRepository.save(u);
    }

    @Transactional
    public UserEntity enable(Long id) {
        UserEntity u = get(id);
        u.setStatus(UserStatus.ACTIVE);
        return userRepository.save(u);
    }
}

// src/main/java/com/example/enterprise/service/TransactionService.java
package com.example.enterprise.service;

import com.example.enterprise.domain.TransactionEntity;
import com.example.enterprise.domain.TransactionStatus;
import com.example.enterprise.domain.UserEntity;
import com.example.enterprise.domain.UserStatus;
import com.example.enterprise.repository.TransactionRepository;
import com.example.enterprise.repository.UserRepository;
import com.example.enterprise.service.dto.CreateTransactionRequest;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.UUID;

@Service
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public TransactionEntity create(CreateTransactionRequest req) {
        UserEntity user = userRepository.findById(req.getUserId())
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        if (user.getStatus() != UserStatus.ACTIVE) {
            throw new IllegalStateException("User is not active");
        }

        TransactionEntity txn = new TransactionEntity();
        txn.setUser(user);
        txn.setAmount(req.getAmount());
        txn.setCurrency(req.getCurrency().toUpperCase());
        txn.setDescription(req.getDescription());
        txn.setStatus(TransactionStatus.PENDING);

        return transactionRepository.save(txn);
    }

    @Transactional(readOnly = true)
    public TransactionEntity getByReferenceId(UUID referenceId) {
        return transactionRepository.findByReferenceId(referenceId)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found"));
    }

    @Transactional(readOnly = true)
    public Page<TransactionEntity> listByUser(Long userId, Pageable pageable) {
        return transactionRepository.findAllByUserId(userId, pageable);
    }

    @Transactional
    public TransactionEntity post(UUID referenceId) {
        TransactionEntity txn = getByReferenceId(referenceId);
        if (txn.getStatus() != TransactionStatus.PENDING) {
            throw new IllegalStateException("Only PENDING transactions can be posted");
        }
        txn.setStatus(TransactionStatus.POSTED);
        return transactionRepository.save(txn);
    }

    @Transactional
    public TransactionEntity fail(UUID referenceId) {
        TransactionEntity txn = getByReferenceId(referenceId);
        if (txn.getStatus() == TransactionStatus.POSTED) {
            throw new IllegalStateException("POSTED transactions cannot be failed");
        }
        txn.setStatus(TransactionStatus.FAILED);
        return transactionRepository.save(txn);
    }

    @Transactional
    public TransactionEntity reverse(UUID referenceId) {
        TransactionEntity txn = getByReferenceId(referenceId);
        if (txn.getStatus() != TransactionStatus.POSTED) {
            throw new IllegalStateException("Only POSTED transactions can be reversed");
        }
        txn.setStatus(TransactionStatus.REVERSED);
        return transactionRepository.save(txn);
    }
}

